"use client"
import Image from "next/image"

const promotions = [
  {
    id: 101,
    badge: "-25%",
    title: { es: "Cortinas tradicionales Blackout y voile texturado o gasa", en: "Sunscreen Combo" },
    description: {
      es: "Cortinas de 2 paños. Cada paño de 1,5 m de ancho x 2,10 m de alto",
      en: "2 traditional blinds blinds up to 1.5m x 2,1m",
    },
    oldPrice: "$305.000",
    newPrice: "$260.000",
    image: "/images/products/sunscreen.jpg", // Asegurate que la ruta exista en /public
  },
  {
    id: 102,
    badge: "-30%",
    title: { es: "Roller Blackout Premium y Sunscreen", en: "Roller Blackout Premium and Sunscreen" },
    description: {
      es: "Cortina blackout premium 1,5 m x 1,5 m + cortina sunscreen 1,5 m x 1,5 m",
      en: "Premium blackout blind with installation included",
    },
    oldPrice: "$350.000",
    newPrice: "$245.000",
    image: "/images/products/blackout.jpg",
  },
]

export default function Promotions({ lang = "es" }: { lang?: "es" | "en" }) {
  return (
    <section className="py-16 bg-background" id="promotions">
      <div className="container mx-auto px-4">
        {/* Banner de Ofertas */}
        <div className="bg-primary text-primary-foreground text-center py-4 mb-12 rounded-lg font-bold text-xl tracking-wide uppercase">
          {lang === "es" 
            ? "PROMOCIONES ESPECIALES" 
            : "SPECIAL OFFERS"}
        </div>

        {/* Grid de Productos */}
        <div className="grid md:grid-cols-2 gap-8 max-w-5xl mx-auto">
          {promotions.map((promo) => (
            <div 
              key={promo.id} 
              className="group relative border border-border rounded-xl overflow-hidden bg-card hover:shadow-xl transition-all duration-300"
            >
              {/* Badge de Descuento */}
              <div className="absolute top-4 left-4 z-10 bg-destructive text-white px-3 py-1 rounded-full text-sm font-bold">
                {promo.badge}
              </div>

              {/* Imagen */}
              <div className="relative h-64 w-full overflow-hidden">
                <Image
                  src={promo.image}
                  alt={promo.title[lang]}
                  fill
                  className="object-cover transition-transform duration-500 group-hover:scale-110"
                />
              </div>

              {/* Info del Producto */}
              <div className="p-6">
                <h3 className="text-2xl font-serif font-semibold mb-2 text-foreground">
                  {promo.title[lang]}
                </h3>
                <p className="text-muted-foreground mb-4 h-12">
                  {promo.description[lang]}
                </p>
                
                <div className="flex items-center gap-4 mb-6">
                  <span className="text-muted-foreground line-through text-lg">
                    {promo.oldPrice}
                  </span>
                  <span className="text-2xl font-bold text-primary">
                    {promo.newPrice}
                  </span>
                </div>

                <button 
                  className="w-full bg-primary text-primary-foreground py-3 rounded-md font-medium hover:opacity-90 transition-opacity"
                  onClick={() => console.log("Contactar por whatsapp:", promo.id)}
                >
                  {lang === "es" ? "Contactar por Whatsapp" : "Consult"}
                </button>
              </div>
            </div>
          ))}
        </div>
      </div>
    </section>
  )
}